#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;

long long gcd(long long a, long long b) {
    while (b) {
        a %= b;
        swap(a, b);
    }
    return a;
}

long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0);

    int n, a0, x, y_input, k, M;
    cin >> n >> a0 >> x >> y_input >> k >> M;

    int k_minus_1 = k - 1;
    long long L = 1;
    if (k_minus_1 > 0) {
        for (int i = 1; i <= k_minus_1; ++i) {
            L = lcm(L, i);
        }
    }

    vector<long long> cnt(L, 0);
    long long sum_x = 0;
    long long current_a = a0;
    sum_x += current_a / L;
    cnt[current_a % L]++;
    for (int i = 1; i < n; ++i) {
        current_a = (current_a * x + y_input) % M;
        sum_x += current_a / L;
        int y = current_a % L;
        cnt[y]++;
    }

    sum_x %= MOD;
    sum_x = sum_x * L % MOD;
    sum_x = sum_x * k % MOD;

    int max_exp = k - 1;
    vector<long long> pow_n(max_exp + 1, 1);
    for (int i = 1; i <= max_exp; ++i) {
        pow_n[i] = pow_n[i - 1] * n % MOD;
    }
    sum_x = sum_x * pow_n[k - 1] % MOD;

    vector<long long> dp_prev(L);
    for (int y = 0; y < L; ++y) {
        dp_prev[y] = cnt[y] % MOD;
    }

    long long ans_y = 0;
    for (int j = 0; j < k; ++j) {
        int exponent = k - j - 1;
        long long t = pow_n[exponent];
        long long contribution = 0;
        for (int y = 0; y < L; ++y) {
            contribution = (contribution + dp_prev[y] * y) % MOD;
        }
        contribution = contribution * t % MOD;
        ans_y = (ans_y + contribution) % MOD;

        int step = j + 1;
        vector<long long> dp_next(L, 0);
        for (int y = 0; y < L; ++y) {
            if (!dp_prev[y]) continue;
            dp_next[y] = (dp_next[y] + dp_prev[y] * (n - 1)) % MOD;
            int y_prime = y - (y % step);
            dp_next[y_prime] = (dp_next[y_prime] + dp_prev[y]) % MOD;
        }
        swap(dp_prev, dp_next);
    }

    long long ans = (sum_x + ans_y) % MOD;
    cout << (ans < 0 ? ans + MOD : ans) << endl;

    return 0;
}

