#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;
const int MAXN = 2e5 + 5;
const int MAXA = 2e5 + 5;
using ll = long long;

vector<int> primes;
bool is_composite[MAXA];
int prime_id[MAXA];
vector<int> prime_factors[MAXA];

void sieve() {
    fill(is_composite, is_composite + MAXA, false);
    for (int i = 2; i < MAXA; ++i) {
        if (!is_composite[i]) {
            prime_id[i] = primes.size();
            primes.push_back(i);
            prime_factors[i].push_back(i);
        }
        for (int p : primes) {
            if (i * p >= MAXA) break;
            is_composite[i * p] = true;
            prime_factors[i * p] = prime_factors[i];
            if (i % p == 0) break;
            prime_factors[i * p].push_back(p);
        }
    }
    for (int i = 2; i < MAXA; ++i) {
        sort(prime_factors[i].begin(), prime_factors[i].end());
        prime_factors[i].erase(unique(prime_factors[i].begin(), prime_factors[i].end()), prime_factors[i].end());
    }
}

vector<int> adj[MAXN];
int A[MAXN];
int depth[MAXN];
int parent[MAXN];
int tin[MAXN], tout[MAXN];
int timer = 0;

void dfs(int u, int p) {
    parent[u] = p;
    depth[u] = (p == -1) ? 0 : depth[p] + 1;
    tin[u] = ++timer;
    for (int v : adj[u]) {
        if (v == p) continue;
        dfs(v, u);
    }
    tout[u] = timer;
}

bool is_ancestor(int u, int v) {
    return tin[u] <= tin[v] && tout[v] <= tout[u];
}

int lca(int u, int v) {
    while (!is_ancestor(u, v)) {
        u = parent[u];
    }
    return u;
}

int main() {
    ios_base::sync_with_stdio(false);
