        adj[v].push_back(u);
    }

    dfs(1, -1);

    vector<vector<int>> nodes_by_prime(primes.size());
    for (int i = 1; i <= N; ++i) {
        for (int p : prime_factors[A[i]]) {
            nodes_by_prime[prime_id[p]].push_back(i);
        }
    }

    ll ans = 0;

    for (size_t pid = 0; pid < primes.size(); ++pid) {
        const auto& nodes = nodes_by_prime[pid];
        int s = nodes.size();
        if (s < 3) continue;

        vector<int> order = nodes;
        sort(order.begin(), order.end(), [&](int a, int b) {
            return tin[a] < tin[b];
        });

        vector<int> stk;
        stk.push_back(order[0]);
        vector<pair<int, int>> edges;

        auto add_edge = [&](int u, int v) {
            edges.emplace_back(u, v);
        };

        for (int i = 1; i < s; ++i) {
            int u = order[i];
            int v = stk.back();
            int w = lca(u, v);

            if (w == v) {
                stk.push_back(u);
                continue;
            }

            while (stk.size() > 1 && depth[stk[stk.size() - 2]] >= depth[w]) {
                add_edge(stk[stk.size() - 2], stk.back());
                stk.pop_back();
            }

            if (stk.back() != w) {
