                stk.pop_back();
                stk.push_back(w);
            }
            stk.push_back(u);
        }

        while (stk.size() > 1) {
            add_edge(stk[stk.size() - 2], stk.back());
            stk.pop_back();
        }

        vector<int> all_nodes;
        all_nodes.push_back(stk[0]);
        for (auto& e : edges) {
            all_nodes.push_back(e.first);
            all_nodes.push_back(e.second);
        }
        sort(all_nodes.begin(), all_nodes.end());
        all_nodes.erase(unique(all_nodes.begin(), all_nodes.end()), all_nodes.end());

        vector<vector<int>> vtree(all_nodes.size());
        vector<int> node_to_idx(MAXN, -1);
        for (size_t i = 0; i < all_nodes.size(); ++i) {
